     1→//! High-level statistical modeling API for Rust
     2→//!
     3→//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
     4→//! and `Glm` (Generalized Linear Models), integrating lower-level crates
     5→//! to provide a complete modeling workflow.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use faer::{prelude::*, Mat};
    11→use ndarray::{ArrayView1, ArrayView2};
    12→
    13→/// Statistical modeling errors
    14→#[derive(thiserror::Error, Debug)]
    15→pub enum ModelError {
    16→    /// Linear algebra computation error
    17→    #[error("Linear algebra error: {0}")]
    18→    LinearAlgebra(String),
    19→    /// Invalid model specification
    20→    #[error("Invalid model: {0}")]
    21→    InvalidModel(String),
    22→}
    23→
    24→/// Common trait for all fitted models
    25→pub trait Fit {
    26→    /// Get model coefficients
    27→    fn coefficients(&self) -> &[f64];
    28→
    29→    /// Get fitted values
    30→    fn fitted(&self) -> &[f64];
    31→
    32→    /// Get residuals
    33→    fn residuals(&self) -> &[f64];
    34→
    35→    /// Get model summary
    36→    fn summary(&self) -> ModelSummary;
    37→}
    38→
    39→/// Model summary information
    40→#[derive(Debug)]
    41→pub struct ModelSummary {
    42→    /// Coefficient table
    43→    pub coefficients: Vec<CoefficientRow>,
    44→    /// R-squared (coefficient of determination)
    45→    pub r_squared: f64,
    46→    /// Adjusted R-squared
    47→    pub adj_r_squared: f64,
    48→    /// Residual standard error
    49→    pub residual_std_error: f64,
    50→    /// F-statistic for overall model significance
    51→    pub f_statistic: f64,
    52→    /// p-value for F-statistic
    53→    pub f_p_value: f64,
    54→    /// Degrees of freedom for model (number of predictors excluding intercept)
    55→    pub df_model: usize,
    56→    /// Degrees of freedom for residuals
    57→    pub df_residual: usize,
    58→}
    59→
    60→/// A row in the coefficient table
    61→#[derive(Debug)]
    62→pub struct CoefficientRow {
    63→    /// Variable name
    64→    pub name: String,
    65→    /// Estimated coefficient
    66→    pub estimate: f64,
    67→    /// Standard error
    68→    pub std_error: f64,
    69→    /// t-statistic
    70→    pub t_value: f64,
    71→    /// p-value
    72→    pub p_value: f64,
    73→}
    74→
    75→/// Linear model fitting
    76→pub struct Lm;
    77→
    78→/// Fitted linear model results
    79→#[derive(Debug)]
    80→pub struct LmFit {
    81→    coefficients: Vec<f64>,
    82→    fitted_values: Vec<f64>,
    83→    residuals: Vec<f64>,
    84→    /// Number of observations
    85→    n_obs: usize,
    86→    /// Matrix rank (for rank-deficient matrices)
    87→    rank: usize,
    88→    /// Design matrix for statistical inference (stored for covariance calculation)
    89→    x_matrix: Mat<f64>,
    90→}
    91→
    92→impl Lm {
    93→    /// Fit a linear model using ndarray views (recommended modern API)
    94→    ///
    95→    /// This implementation uses faer's column-pivoted QR decomposition to handle
    96→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    97→    ///
    98→    /// # Arguments
    99→    /// * `x` - Design matrix as ndarray view (n_observations × n_predictors)
   100→    /// * `y` - Response vector as ndarray view (n_observations)
   101→    ///
   102→    /// # Example
   103→    /// ```
   104→    /// use ndarray::Array2;
   105→    /// use stats_models::Lm;
   106→    ///
   107→    /// // Create design matrix with intercept
   108→    /// let x = Array2::from_shape_vec((3, 2), vec![1.0, 1.0, 1.0, 2.0, 1.0, 3.0]).unwrap();
   109→    /// let y = vec![3.0, 5.0, 7.0];
   110→    ///
   111→    /// let fit = Lm::fit_ndarray(x.view(), ndarray::Array1::from(y).view()).unwrap();
   112→    /// ```
   113→    pub fn fit_ndarray(x: ArrayView2<f64>, y: ArrayView1<f64>) -> Result<LmFit, ModelError> {
   114→        let (n_rows, n_cols) = x.dim();
   115→
   116→        if y.len() != n_rows {
   117→            return Err(ModelError::InvalidModel(
   118→                "Response vector length doesn't match number of observations".to_string(),
   119→            ));
   120→        }
   121→
   122→        // Convert to faer matrices
   123→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x[[i, j]]);
   124→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y[i]);
   125→
   126→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   127→    }
   128→
   129→    /// Fit a linear model using raw slices (legacy API for backward compatibility)
   130→    ///
   131→    /// This implementation uses faer's column-pivoted QR decomposition to handle
   132→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
   133→    ///
   134→    /// **Note**: Consider using `fit_ndarray` for better type safety and ergonomics.
   135→    pub fn fit(
   136→        x_data: &[f64],
   137→        y_data: &[f64],
   138→        n_rows: usize,
   139→        n_cols: usize,
   140→    ) -> Result<LmFit, ModelError> {
   141→        if x_data.len() != n_rows * n_cols {
   142→            return Err(ModelError::InvalidModel(
   143→                "Design matrix dimensions don't match data".to_string(),
   144→            ));
   145→        }
   146→
   147→        if y_data.len() != n_rows {
   148→            return Err(ModelError::InvalidModel(
   149→                "Response vector length doesn't match number of observations".to_string(),
   150→            ));
   151→        }
   152→
   153→        // Create faer matrices from input data
   154→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
   155→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
   156→
   157→        Self::fit_internal(x_mat, y_mat, n_rows, n_cols)
   158→    }
   159→
   160→    /// Internal fitting logic shared by both APIs
   161→    fn fit_internal(
   162→        x_mat: Mat<f64>,
   163→        y_mat: Mat<f64>,
   164→        n_rows: usize,
   165→        n_cols: usize,
   166→    ) -> Result<LmFit, ModelError> {
   167→        // Use column-pivoted QR for numerical stability with rank-deficient matrices
   168→        let qr = x_mat.col_piv_qr();
   169→
   170→        // Calculate rank from R matrix diagonal elements
   171→        let r_matrix = qr.R();
   172→        let tolerance = 1e-12;
   173→        let mut rank = 0;
   174→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
   175→            if r_matrix[(i, i)].abs() > tolerance {
   176→                rank += 1;
   177→            }
   178→        }
   179→
   180→        // Handle rank-deficient matrices by checking for numerical instability
   181→        let coefficients_mat = qr.solve_lstsq(&y_mat);
   182→
   183→        // Check for numerical instability and apply correction if needed
   184→        let has_instability =
   185→            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);
   186→
   187→        let final_coefficients_mat = if has_instability {
   188→            // For rank-deficient case, set coefficients for columns beyond rank to zero
   189→            let mut corrected_coefs = Vec::new();
   190→            for i in 0..coefficients_mat.nrows() {
   191→                let coef = coefficients_mat[(i, 0)];
   192→                if coef.abs() > 1e10 {
   193→                    corrected_coefs.push(0.0);
   194→                } else {
   195→                    corrected_coefs.push(coef);
   196→                }
   197→            }
   198→            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
   199→        } else {
   200→            coefficients_mat
   201→        };
   202→
   203→        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
   204→        let fitted_mat = &x_mat * &final_coefficients_mat;
   205→
   206→        // Calculate residuals: e = y - ŷ
   207→        let residuals_mat = &y_mat - &fitted_mat;
   208→
   209→        // Extract results to plain Vec<f64> for API
   210→        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
   211→            .map(|i| final_coefficients_mat[(i, 0)])
   212→            .collect();
   213→
   214→        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
   215→            .map(|i| fitted_mat[(i, 0)])
   216→            .collect();
   217→
   218→        let residuals: Vec<f64> = (0..residuals_mat.nrows())
   219→            .map(|i| residuals_mat[(i, 0)])
   220→            .collect();
   221→
   222→        // rank is already computed above using qr.rank()
   223→
   224→        Ok(LmFit {
   225→            coefficients,
   226→            fitted_values,
   227→            residuals,
   228→            n_obs: n_rows,
   229→            rank,
   230→            x_matrix: x_mat,
   231→        })
   232→    }
   233→}
   234→
   235→impl LmFit {
   236→    /// Get the number of observations used in the model
   237→    pub fn n_obs(&self) -> usize {
   238→        self.n_obs
   239→    }
   240→
   241→    /// Get the rank of the design matrix (number of linearly independent columns)
   242→    pub fn rank(&self) -> usize {
   243→        self.rank
   244→    }
   245→
   246→    /// Get degrees of freedom for error (n_obs - rank)
   247→    pub fn df_resid(&self) -> usize {
   248→        self.n_obs.saturating_sub(self.rank)
   249→    }
   250→}
   251→
   252→impl Fit for LmFit {
   253→    fn coefficients(&self) -> &[f64] {
   254→        &self.coefficients
   255→    }
   256→
   257→    fn fitted(&self) -> &[f64] {
   258→        &self.fitted_values
   259→    }
   260→
   261→    fn residuals(&self) -> &[f64] {
   262→        &self.residuals
   263→    }
   264→
   265→    fn summary(&self) -> ModelSummary {
   266→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   267→
   268→        // Calculate residual standard error: s² = RSS / (n - p)
   269→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   270→        let df_resid = self.df_resid() as f64;
   271→        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
   272→        let residual_std_error = mse.sqrt();
   273→
   274→        // Calculate Total Sum of Squares (TSS) and R-squared
   275→        let y_mean: f64 = self
   276→            .fitted_values
   277→            .iter()
   278→            .zip(self.residuals.iter())
   279→            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
   280→            .sum::<f64>()
   281→            / self.n_obs as f64;
   282→
   283→        let tss: f64 = self
   284→            .fitted_values
   285→            .iter()
   286→            .zip(self.residuals.iter())
   287→            .map(|(fitted, resid)| {
   288→                let y = fitted + resid;
   289→                (y - y_mean).powi(2)
   290→            })
   291→            .sum();
   292→
   293→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   294→
   295→        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
   296→        let n = self.n_obs as f64;
   297→        let p = self.rank as f64;
   298→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   299→            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
   300→        } else {
   301→            r_squared
   302→        };
   303→
   304→        // F-statistic for overall model significance
   305→        // RSS for null model (intercept only) equals TSS
   306→        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
   307→        let f_statistic = if df_model > 0 {
   308→            model_f_statistic(rss, tss, df_model, self.df_resid())
   309→        } else {
   310→            0.0
   311→        };
   312→
   313→        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
   314→            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
   315→        } else {
   316→            1.0
   317→        };
   318→
   319→        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
   320→        // Compute X'X
   321→        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   322→
   323→        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
   324→        let qr = xtx.col_piv_qr();
   325→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   326→        let xtx_inv = qr.solve(&identity);
   327→
   328→        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
   329→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   330→            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
   331→            .collect();
   332→
   333→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   334→        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);
   335→
   336→        let mut coefficient_rows = Vec::new();
   337→        for (i, &coef) in self.coefficients.iter().enumerate() {
   338→            let name = if i == 0 {
   339→                "Intercept".to_string()
   340→            } else {
   341→                format!("X{}", i)
   342→            };
   343→
   344→            coefficient_rows.push(CoefficientRow {
   345→                name,
   346→                estimate: coef,
   347→                std_error: std_errors[i],
   348→                t_value: t_stats[i],
   349→                p_value: p_values[i],
   350→            });
   351→        }
   352→
   353→        ModelSummary {
   354→            coefficients: coefficient_rows,
   355→            r_squared,
   356→            adj_r_squared,
   357→            residual_std_error,
   358→            f_statistic,
   359→            f_p_value,
   360→            df_model,
   361→            df_residual: self.df_resid(),
   362→        }
   363→    }
   364→}
   365→
   366→#[cfg(test)]
   367→mod tests {
   368→    use super::*;
   369→
   370→    #[test]
   371→    fn test_lm_fit_basic() {
   372→        // Simple 2x2 identity matrix with response
   373→        let x_data = vec![1.0, 0.0, 0.0, 1.0]; // 2x2 identity
