   567→    fn test_multicollinearity_debug() {
   568→        // Test with non-collinear data to check if our fix works
   569→        let n_obs = 8;
   570→        let x1_values: Vec<f64> = (1..=n_obs).map(|i| i as f64).collect();
   571→        let x2_values: Vec<f64> = (1..=n_obs)
   572→            .map(|i| (i as f64) * 0.3 + 0.1 * (i as f64).powi(2))
   573→            .collect();
   574→        let y_values: Vec<f64> = x1_values
   575→            .iter()
   576→            .zip(x2_values.iter())
   577→            .map(|(&x1, &x2)| 2.0 + 1.5 * x1 + 0.8 * x2 + 0.1 * x1 * x2.sin())
   578→            .collect();
   579→
   580→        // Design matrix: [1, x1, x2] - now without perfect multicollinearity
   581→        let mut x_data = Vec::with_capacity(n_obs * 3);
   582→        for i in 0..n_obs {
   583→            x_data.push(1.0); // intercept
   584→            x_data.push(x1_values[i]); // x1
   585→            x_data.push(x2_values[i]); // x2
   586→        }
   587→
   588→        println!("=== Multiple Regression Debug ===");
   589→        println!("x1: {:?}", x1_values);
   590→        println!("x2: {:?}", x2_values);
   591→        println!("x2 is not perfectly correlated with x1");
   592→
   593→        let x_mat = Mat::from_fn(n_obs, 3, |i, j| x_data[i * 3 + j]);
   594→        let _y_mat = Mat::from_fn(n_obs, 1, |i, _| y_values[i]);
