//! Link functions for generalized linear models
//!
//! This crate provides Zero-Sized Types (ZSTs) representing GLM link functions,
//! enabling compile-time dispatch for model-fitting algorithms with no runtime overhead.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

/// Trait for link functions
pub trait LinkFn {
    /// Apply the link function
    fn link(&self, mu: f64) -> f64;

    /// Apply the inverse link function  
    fn inverse_link(&self, eta: f64) -> f64;

    /// Derivative of the inverse link function
    fn mu_eta(&self, eta: f64) -> f64;
}

/// Identity link function
#[derive(Debug, Default)]
pub struct Identity;

impl LinkFn for Identity {
    fn link(&self, mu: f64) -> f64 {
        mu
    }

    fn inverse_link(&self, eta: f64) -> f64 {
        eta
    }

    fn mu_eta(&self, _eta: f64) -> f64 {
        1.0
    }
}

/// Log link function
#[derive(Debug, Default)]
pub struct Log;

impl LinkFn for Log {
    fn link(&self, mu: f64) -> f64 {
        mu.ln()
    }

    fn inverse_link(&self, eta: f64) -> f64 {
        eta.exp()
    }

    fn mu_eta(&self, eta: f64) -> f64 {
        eta.exp()
    }
}

/// Logit link function
#[derive(Debug, Default)]
pub struct Logit;

impl LinkFn for Logit {
    fn link(&self, mu: f64) -> f64 {
        (mu / (1.0 - mu)).ln()
    }

    fn inverse_link(&self, eta: f64) -> f64 {
        let exp_eta = eta.exp();
        exp_eta / (1.0 + exp_eta)
    }

    fn mu_eta(&self, eta: f64) -> f64 {
        let exp_eta = eta.exp();
        exp_eta / (1.0 + exp_eta).powi(2)
    }
}

