) -> Result<Array1<f64>, OptimError> {
    let (n_obs, n_vars) = x.dim();

    // Create weight matrix W^(1/2) for numerical stability
    let sqrt_weights = weights.mapv(|w| w.sqrt());

    // Create weighted design matrix: X_w = W^(1/2) * X
    let x_weighted = Mat::from_fn(n_obs, n_vars, |i, j| sqrt_weights[i] * x[[i, j]]);

    // Create weighted response: z_w = W^(1/2) * z
    let z_weighted = Mat::from_fn(n_obs, 1, |i, _| sqrt_weights[i] * z[i]);

    // Solve using QR decomposition for numerical stability
    let qr = x_weighted.col_piv_qr();
    let beta_mat = qr.solve_lstsq(&z_weighted);

    Ok(Array1::from_iter((0..n_vars).map(|i| beta_mat[(i, 0)])))
}

